const breezeUrl = Cypress.env('NEXT_PUBLIC_BREEZE_URL');
const postActivationPageUrl = `${breezeUrl}/sv-se/products/${calcAccepted.id}/request-received`;

describe('post activation form', () => {
  beforeEach(() => {
    cy.intercept('GET', '/web/interests/mountingsurfaces', mountingSurface);

    cy.intercept('GET', '/web/customforms/post-activation/**', postActivation);
    cy.intercept('POST', `/web/interests/${calcAccepted.id}/activate`, {
      statusCode: 204,
    });
    cy.intercept(
      'POST',
      '/web/user_validation/validate_phone_number',
      validatePhoneNumber,
    );
  });

  function configureIntercepts(interest) {
    cy.intercept('GET', `**/web/interests/${interest.id}/`, interest);
    cy.intercept(
      'GET',
      `**/web/interests/${interest.id}/products/`,
      interest.products,
    );
    cy.intercept(
      'POST',
      `**/web/interests/${interest.id}/user_form_interaction/`,
      {},
    ).as('userFormInteraction');
    cy.intercept(
      'POST',
      `**/web/interests/${interest.id}/user_form_question_interaction/`,
      {},
    ).as('userFormQuestionInteraction');
  }

  describe('post-activation form', () => {
    beforeEach(() => {
      configureIntercepts(calcAccepted);
    });

    it('should be able to go through all the steps', () => {
      cy.visit(postActivationPageUrl);

      const [, ...questions] = postActivation.questions;
      questions
        .filter((question, idx) => idx <= questions.length)
        .forEach(() => {
          cy.get('[data-testid="post-activation-forward"]').click();
        });
    });

    it('should display all summary content', () => {
      cy.visit(postActivationPageUrl);

      cy.get('[data-testid="post-activation-summary-product-panels"]').should(
        'be.visible',
      );
      cy.get('[data-testid="post-activation-summary-product-battery"]').should(
        'be.visible',
      );
      cy.get(
        '[data-testid="post-activation-summary-product-ev-charger"]',
      ).should('be.visible');
      cy.get(
        `[data-testid="post-activation-summary-purchase-${purchaseModelCode.LOAN}"]`,
      ).should('be.visible');
      cy.get(
        `[data-testid="post-activation-summary-purchase-${purchaseModelCode.LEASING}"]`,
      ).should('be.visible');
      cy.get(
        `[data-testid="post-activation-summary-purchase-${purchaseModelCode.BUY_NOW}"]`,
      ).should('be.visible');
    });
  });
});
