import { referralSourceEnum } from '@otovo/shared/cloudEnums';
import { useReferralCode } from '@otovo/shared/components/Referrals/useReferralCode';
import { useGlobalConfig } from '@otovo/shared/hooks/configContext';
import {
  Cloud$Interest,
  Cloud$PostActivationQuestion,
} from '@otovo/shared/types/cloudApi';
import { useSearchParams } from 'next/navigation';
import { useEffect, useState } from 'react';
import { Wizard } from 'react-use-wizard';
import { Footer } from './Wizard/Footer';
import { QuestionStep } from './Wizard/Steps/QuestionStep';
import ReferralStep from './Wizard/Steps/ReferralStep';
import { StepWrapper } from './Wizard/components/StepWrapper';

type Props = {
  interest: Cloud$Interest;
  questions: Array<Cloud$PostActivationQuestion>;
  onAnswerChange: (isAnswered: boolean) => void;
  onComplete: () => void;
  onPhotoUpload: () => void;
  setActiveStep: (step: number) => void;
};

const Questions = ({
  interest,
  questions,
  onAnswerChange,
  onComplete,
  onPhotoUpload,
  setActiveStep,
}: Props) => {
  const currentSearchParams = useSearchParams();
  const config = useGlobalConfig();

  const startQuestionOverride = currentSearchParams.get('pa_s');

  const [screenHeight, setScreenHeight] = useState(0);
  const { BU_CONFIG } = config;

  useEffect(() => {
    setScreenHeight(window.innerHeight);
  }, []);

  // iPhone 6 has the smallest screen height we support for illustrations
  const iphone6Height = 667;
  const showIllustrations = screenHeight >= iphone6Height;

  const { email, customer_name: customerName } = interest;

  const { referralCode } = useReferralCode({
    email,
    name: customerName,
    client_source: referralSourceEnum.POST_ACTIVATION_FORM,
  });

  const isFrance = BU_CONFIG.market === 'fr';

  const handleStepChange = (step: number) => {
    setActiveStep(step);
  };

  const sortedQuestions = [...questions].sort((a, b) => {
    // Sort questions to show "mounting_surface" first based on the 'pa_s' query parameter.
    // This feature is used in customer comms from HubSpot
    if (a.name === startQuestionOverride) return -1;
    if (b.name === startQuestionOverride) return 1;
    return 0;
  });

  return (
    <Wizard
      footer={
        <Footer
          stepNames={sortedQuestions.map((question) => question.name)}
          onComplete={onComplete}
        />
      }
      onStepChange={handleStepChange}
    >
      {sortedQuestions.map((question) => (
        <StepWrapper key={question.name}>
          <QuestionStep
            interestId={interest.id}
            showIllustrations={showIllustrations}
            question={question}
            onAnswerChange={onAnswerChange}
            onPhotoUpload={onPhotoUpload}
          />
        </StepWrapper>
      ))}
      {referralCode && !isFrance && (
        <StepWrapper>
          <ReferralStep
            showIllustrations={showIllustrations}
            referralCode={referralCode}
          />
        </StepWrapper>
      )}
    </Wizard>
  );
};

export default Questions;
