import { Box } from '@otovo/rainbow';
import CenterSpinner from '@otovo/shared/components/LoadingScreens/CenterSpinner';
import {
  Cloud$MountingSurface,
  Cloud$MountingSurfaceSlug,
} from '@otovo/shared/types/cloudApi';
import { useMountingSurfaceDetails } from '../CalcPage/sections/SurfaceSection/useMontingSurfaces';
import MountingSurface from './MountingSurface';

type Props = {
  onRoofSelect: (arg1: Cloud$MountingSurfaceSlug | null | undefined) => void;
  selectedMountingSurface: Cloud$MountingSurfaceSlug | null | undefined;
  darkMode?: boolean;
  excludeOther?: boolean;
};

function MountingSurfaceSelector({
  onRoofSelect,
  selectedMountingSurface,
  darkMode,
  excludeOther,
}: Props) {
  const { mountingSurfaces, error } = useMountingSurfaceDetails({
    excludeOther,
  });

  if (!mountingSurfaces || error) {
    return (
      <div>
        <CenterSpinner height="h-full" />
      </div>
    );
  }

  // We want to have other as viable option, even though it is not active in all markets
  // This allows markets to use it to disqualify customers

  const otherSurfaceSlug = 'other';

  return (
    <fieldset data-testid="mounting-surface-selector">
      <legend className="sr-only">Select mounting surface type</legend>
      <Box
        display="grid"
        gridTemplateColumns="repeat(auto-fill, minmax(120px, 1fr))"
        gridAutoRows="1fr"
        gridGap="3"
      >
        {mountingSurfaces
          .filter(
            (mountingSurface: Cloud$MountingSurface) =>
              mountingSurface.active ||
              mountingSurface.slug === selectedMountingSurface ||
              mountingSurface.slug === otherSurfaceSlug,
          )
          .map((mountingSurface: Cloud$MountingSurface, index) => (
            <MountingSurface
              onRoofSelect={onRoofSelect}
              selectedMountingSurface={selectedMountingSurface}
              key={mountingSurface.slug}
              mountingSurface={mountingSurface}
              darkMode={darkMode}
              // eslint-disable-next-line jsx-a11y/no-autofocus
              autoFocus={
                selectedMountingSurface
                  ? selectedMountingSurface === mountingSurface.slug
                  : index === 0
              }
            />
          ))}
      </Box>
    </fieldset>
  );
}

export default MountingSurfaceSelector;
